// === DECLARING AN INTERFACE ===
// MyInterface.h
#pragma once
#include "CoreMinimal.h"
#include "UObject/Interface.h"
#include "MyInterface.generated.h"

UINTERFACE(MinimalAPI, Blueprintable)
class UInteractable : public UInterface {
    GENERATED_BODY()
};

class IInteractable {
    GENERATED_BODY()
public:
    // Pure C++ interface function
    virtual void Interact(AActor* Caller) = 0;

    // Or Blueprint-compatible version:
    // UFUNCTION(BlueprintCallable, BlueprintNativeEvent, Category="Interaction")
    // void Interact(AActor* Caller);
};

// === FULL PATTERN: Interactable Interface ===

// --- Interface Declaration (Interactable.h) ---
UINTERFACE(MinimalAPI, Blueprintable)
class UInteractable : public UInterface {
    GENERATED_BODY()
};

class IInteractable {
    GENERATED_BODY()
public:
    UFUNCTION(BlueprintCallable, BlueprintNativeEvent, Category="Interaction")
    FText GetInteractText();

    UFUNCTION(BlueprintCallable, BlueprintNativeEvent, Category="Interaction")
    void Interact(AActor* Caller);
};

// --- Implementing on a Door (Door.h) ---
UCLASS()
class ADoor : public AActor, public IInteractable {
    GENERATED_BODY()
public:
    // _Implementation suffix is required for BlueprintNativeEvent
    virtual FText GetInteractText_Implementation() override {
        return bIsOpen ? FText::FromString("Close Door") : FText::FromString("Open Door");
    }

    virtual void Interact_Implementation(AActor* Caller) override {
        bIsOpen = !bIsOpen;
        PlayDoorAnimation();
    }

private:
    bool bIsOpen = false;
};

// --- Calling from Player (PlayerCharacter.cpp) ---
void AMyPlayer::TryInteract() {
    FHitResult Hit;
    // Line trace forward...

    AActor* HitActor = Hit.GetActor();
    if (HitActor && HitActor->Implements<UInteractable>()) {
        // This correctly calls Blueprint or C++ implementation
        IInteractable::Execute_Interact(HitActor, this);

        FText Text = IInteractable::Execute_GetInteractText(HitActor);
        ShowInteractUI(Text);
    }
}

// Blueprint Interface workflow (described for reference):
//
// 1. Create BPI_Interactable in Content Browser > Blueprint > Blueprint Interface
// 2. Add function: Interact(Caller: Actor) and GetInteractText() -> Text
// 3. Open BP_Door > Class Settings > Interfaces > Add BPI_Interactable
// 4. In EventGraph: right-click > Add Event > Interact (from BPI_Interactable)
// 5. Implement the logic in the EventGraph
//
// Calling from another Blueprint:
// 1. Get reference to the target actor
// 2. Use 'Does Implement Interface' node to check (optional but recommended)
// 3. Use 'Interact (Message)' node — this calls through the interface
//
// In C++ calling a Blueprint Interface:
if (Actor->GetClass()->ImplementsInterface(UInteractable::StaticClass())) {
    IInteractable::Execute_Interact(Actor, this);
}

// === DAMAGEABLE INTERFACE ===
UINTERFACE(Blueprintable)
class UDamageable : public UInterface { GENERATED_BODY() };

class IDamageable {
    GENERATED_BODY()
public:
    UFUNCTION(BlueprintCallable, BlueprintNativeEvent)
    float ApplyDamage(float Amount, const FDamageInfo& Info);

    UFUNCTION(BlueprintCallable, BlueprintNativeEvent)
    bool IsAlive();

    UFUNCTION(BlueprintCallable, BlueprintNativeEvent)
    float GetCurrentHealth();
};

// Character implements it
class AMyCharacter : public ACharacter, public IDamageable {
    GENERATED_BODY()
    float Health = 100.f;

    virtual float ApplyDamage_Implementation(float Amount, const FDamageInfo& Info) override {
        Health = FMath::Max(Health - Amount, 0.f);
        if (Health <= 0.f) Die();
        return Amount;
    }
    virtual bool IsAlive_Implementation() override { return Health > 0.f; }
    virtual float GetCurrentHealth_Implementation() override { return Health; }
};

// Barrel implements it differently
class AExplodingBarrel : public AActor, public IDamageable {
    GENERATED_BODY()
    float Integrity = 50.f;

    virtual float ApplyDamage_Implementation(float Amount, const FDamageInfo& Info) override {
        Integrity -= Amount;
        if (Integrity <= 0.f) Explode();  // Different reaction!
        return Amount;
    }
    virtual bool IsAlive_Implementation() override { return Integrity > 0.f; }
    virtual float GetCurrentHealth_Implementation() override { return Integrity; }
};

// Caller doesn't care about the type
void AMyWeapon::OnHit(AActor* HitActor) {
    if (HitActor->Implements<UDamageable>()) {
        IDamageable::Execute_ApplyDamage(HitActor, 25.f, DamageInfo);
    }
}
